// Fast — walks memory in order (spatial locality).
// The CPU pre-fetches the next chunk while you use the current one.
var sum = 0;
for (var row = 0; row < 1000; row++) {
  for (var col = 0; col < 1000; col++) {
    sum += matrix[row][col];   // rows are stored together in memory
  }
}

// SLOW — jumps around in memory (bad spatial locality).
// Every access is a fresh cache miss; the CPU stalls waiting for RAM.
for (var col = 0; col < 1000; col++) {
  for (var row = 0; row < 1000; row++) {
    sum += matrix[row][col];   // jumps 1000 elements every step
  }
}

// Both give the same answer.
// The first can be 5–10× faster on a real machine.

// File: cache_demo.dart
// Run: dart cache_demo.dart
import 'dart:typed_data';

void main() {
  const n = 2000;
  // A flat 2000×2000 grid of integers, stored row-major.
  final grid = Int32List(n * n);
  for (var i = 0; i < grid.length; i++) grid[i] = i;

  // --- Fast pattern: read row by row ---
  final t1 = DateTime.now();
  var sum1 = 0;
  for (var row = 0; row < n; row++) {
    for (var col = 0; col < n; col++) {
      sum1 += grid[row * n + col];
    }
  }
  final ms1 = DateTime.now().difference(t1).inMilliseconds;

  // --- Slow pattern: read column by column ---
  final t2 = DateTime.now();
  var sum2 = 0;
  for (var col = 0; col < n; col++) {
    for (var row = 0; row < n; row++) {
      sum2 += grid[row * n + col];
    }
  }
  final ms2 = DateTime.now().difference(t2).inMilliseconds;

  print('Row-major (fast):    $ms1 ms   sum=$sum1');
  print('Column-major (slow): $ms2 ms   sum=$sum2');
  print('Slow / Fast ratio:   ${(ms2 / ms1).toStringAsFixed(1)}×');
}

// Expected output on a typical laptop:
//   Row-major (fast):    35 ms   sum=7998000000
//   Column-major (slow): 240 ms  sum=7998000000
//   Slow / Fast ratio:   6.8×
//
// The SAME numbers, the SAME total operations, but almost 7× slower
// because the second loop makes the CPU wait for RAM on every read.
